LANG_INDEX = {'tr': 0, 'en': 1, 'es': 2, 'ru': 3, 'hy': 4}

def get_replacements(lang):
    if lang == 'tr':
        return {
            'assets/gor_main.jpg': '../gor_main_pres.jpg',
            'assets/gor_main_pres.jpg': '../gor_main_pres.jpg',
        }
    idx = LANG_INDEX[lang]
    meta = LANG_META[lang]
    reps = {
        'lang="tr"': f'lang="{meta["lang"]}"',
        'Global AI & Ekonomi Strateji Sunumu': meta['title'].split('|', 1)[1].strip() if '|' in meta['title'] else meta['title'],
        'Slayt': meta['slide'],
        'assets/gor_main.jpg': '../gor_main_pres.jpg',
        'assets/gor_main_pres.jpg': '../gor_main_pres.jpg',
    }
    for pair in PAIRS:
        tr_text = pair[0]
        if tr_text in reps:
            continue
        reps[tr_text] = pair[idx]
    # dil rozetleri - tum slide'larda
    badge_old = '<span class="active">TR</span><span>EN</span><span>ES</span><span>RU</span><span>HY</span>'
    badge_plain = '<span>TR</span><span>EN</span><span>ES</span><span>RU</span><span>HY</span>'
    badges = lang_badges(meta['active'])
    reps[badge_old] = badges
    reps[badge_plain] = badges
    return reps
